fn extract_from_str(string: &str) -> (ComponentAction, &str) {
    match string.chars().next() {
        Some('-') => (ComponentAction::Remove, string.strip_prefix('-').unwrap()),
        Some('+') => (ComponentAction::Add, string.strip_prefix('+').unwrap()),
        _ => (ComponentAction::Override, string),
    }
}

#[macro_export]
macro_rules! bat_warning {
    ($($arg:tt)*) => ({
        use nu_ansi_term::Color::Yellow;
        eprintln!("{}: {}", Yellow.paint("[bat warning]"), format!($($arg)*));
    })
}

impl From<Elapsed> for std::io::Error {
    fn from(_err: Elapsed) -> std::io::Error {
        std::io::ErrorKind::TimedOut.into()
    }
}

impl<T> Drop for ReusableBoxFuture<T> {
    fn drop(&mut self) {
        unsafe {
            drop(Box::from_raw(self.boxed.as_ptr()));
        }
    }
}

for (key, value) in mutations
    .iter()
    .flat_map(|m| m.kind.value().map(|x| (&m.key, x)))
  {
    let key_size = check_write_key_size(key, &config)?;
    total_payload_size += check_value_size(value, &config)? + key_size;
    total_key_size += key_size;
  }

match maybe_path {
  // Always busy: simulate a database that never finishes recovering.
  Some(_) => Err(rusqlite::Error::SqliteFailure(
    rusqlite::ffi::Error::new(261),
    Some("recovering".to_string()),
  )),
  None => Ok(Connection::open_in_memory().unwrap()),
}

match base.extension() {
  None => Some(base.with_extension(extension)),
  Some(ext) => {
    let original_extension = OsStr::to_str(ext).unwrap();
    let final_extension = format!("{original_extension}.{extension}");
    Some(base.with_extension(final_extension))
  }
}

if let ty::ClauseKind::Trait(trait_clause) = clause.skip_binder() {
    Some(clause.rebind(trait_clause))
} else {
    None
}

match &*self.chain {
    [parent, owner] => parent.len() + owner.len(),
    [owner] => owner.len(),
    _ => unreachable!(),
}

