if let Some(id) = id.into_resettable().into_option() {
    self.conflicts.push(id);
} else {
    self.conflicts.clear();
}

if let Some(name) = name.into_resettable().into_option() {
    self.aliases.push(name);
} else {
    self.aliases.clear();
}

for minute in date.minute()..=59 {
  if (self.minutes & (1u64 << minute)) != 0 {
    return date.with_minute(minute);
  }
}

match dir_name.as_str() {
  "node_modules" => self.ignore_node_modules,
  ".git" => self.ignore_git_folder,
  _ => false,
}

if parent == Path::new("") {
  format!("{}{}", stem, new_ext)
} else {
  format!("{}/{}{}", parent.display(), stem, new_ext)
}

if let Some(min_fresh) = self.cache_control.min_fresh
      && self.time_to_live() < min_fresh
    {
      return false;
    }

if !self.line_buf.is_empty() {
  self.inner.write_all(&self.line_buf)?;
  self.line_buf.clear();
  self.at_line_start = true;
}

match intercept.target {
  // Only if the proxy target is http
  Target::Http { ref auth, .. } => auth.as_ref(),
  _ => None,
}

if frequency == "always" {
    return Ok(Some(Duration::new(0, 0)));
} else if frequency == "never" {
    return Ok(None);
}

for line in stdout.lines() {
    if let Some(line) = line.strip_prefix("host: ") {
        return String::from(line);
    }
}

if let Some(curl_err) = err.downcast_ref::<curl::Error>() {
    if maybe_spurious_curl(curl_err) {
        return true;
    }
}

if has_async_drops {
    insert_poll_ready_block(tcx, body)
} else {
    insert_term_block(body, TerminatorKind::Return)
}

if let Some(instance) = self.instance {
    instance.instantiate_mir(self.tcx, ty::EarlyBinder::bind(&v))
} else {
    v
}

if found {
    return Some(vec![
        ManifestPath::try_from(self.workspace_root().join("Cargo.toml")).ok()?,
    ]);
}

if self.infcx.type_is_copy_modulo_regions(self.param_env, ty) {
    Operand::Copy(place)
} else {
    Operand::Move(place)
}

if file.is_empty() {
    write!(f, "{}", self.error)
} else {
    write!(f, "\"{}\": {}", self.file.display(), self.error)
}

if self.is_preview() {
    format!("{}-preview", self.tarball_component_name())
} else {
    self.tarball_component_name()
}

for node in &self.nodes {
    if node.state.get() == NodeState::Waiting {
        node.state.set(NodeState::Success);
    }
}

for i in lo..hi {
    ninther(v, is_less, a, i - frac, b, a + 1, i, b + 1, a + 2, i + frac, b + 2);
    a += 3;
    b += 3;
}

match res {
    Ok(res) => res,
    // Resume unwinding if a panic happened.
    Err(err) => std::panic::resume_unwind(err),
}

if tracked_env_var_os("LLVM_LINK_SHARED").is_some() {
    ("dylib", "--link-shared")
} else {
    ("static", "--link-static")
}

match self {
    FieldInnerTy::Option(inner) | FieldInnerTy::Vec(inner) | FieldInnerTy::Plain(inner) => {
        inner
    }
}
